import{_ as t,o as a,c as i,a3 as s}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Platform Production Deployment Runbook","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Platform Production Deployment Runbook | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/platform-production-runbook"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Platform Production Deployment Runbook | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/platform-production-runbook"}]]},"headers":[],"relativePath":"deployment/platform-production-runbook.md","filePath":"deployment/platform-production-runbook.md","lastUpdated":1784419868000}'),o={name:"deployment/platform-production-runbook.md"};function n(r,e,d,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="platform-production-deployment-runbook" tabindex="-1">Platform Production Deployment Runbook <a class="header-anchor" href="#platform-production-deployment-runbook" aria-label="Permalink to &quot;Platform Production Deployment Runbook&quot;">​</a></h1><p>This is the single ops checklist for launching the SaleOS platform (Central + Tenant applications) to paying customers.</p><p>Domain production guides still apply for auth, billing, RBAC, modules, Leads, and Tasks. This document covers <strong>platform-wide</strong> process requirements.</p><p>RC notes: <a href="/deployment/rc1-production-readiness">releases/rc1-production-readiness.md</a>.</p><h2 id="launch-blockers-must-be-green" tabindex="-1">Launch blockers (must be green) <a class="header-anchor" href="#launch-blockers-must-be-green" aria-label="Permalink to &quot;Launch blockers (must be green)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Requirement</th></tr></thead><tbody><tr><td><code>APP_ENV</code></td><td><code>production</code></td></tr><tr><td><code>APP_DEBUG</code></td><td><code>false</code> (boot throws if true in production)</td></tr><tr><td><code>APP_KEY</code></td><td>Set and backed up</td></tr><tr><td><code>FRONTEND_URL</code> / <code>CORS_ALLOWED_ORIGINS</code></td><td>Pin SPA origins (no <code>*</code>)</td></tr><tr><td><code>STRIPE_WEBHOOK_SECRET</code> / <code>CREEM_WEBHOOK_SECRET</code></td><td>Non-empty for each <strong>active</strong> gateway</td></tr><tr><td>Cache</td><td>Prefer <code>CACHE_STORE=redis</code>. Isolation uses <strong>explicit tenant-scoped keys</strong> (<code>CacheTenancyBootstrapper</code> is intentionally off — do not rely on Redis tags alone)</td></tr><tr><td>Queue worker</td><td>Always running (<code>queue:work --queue=emails,default</code> or Laravel Cloud background process)</td></tr><tr><td>Reverb</td><td>Supervised process, public TLS endpoint, SPA origin pinned</td></tr><tr><td>Scheduler</td><td>Cron/<code>schedule:run</code> every minute</td></tr><tr><td>HTTPS</td><td>TLS at edge; app trusts proxies (<code>TrustProxies</code>); production forces <code>https</code> URL scheme; <code>SESSION_SECURE_COOKIE=true</code></td></tr><tr><td>Registration</td><td><code>registration_enabled</code> intentional (defaults <strong>false</strong>)</td></tr><tr><td>Health</td><td><code>GET /up</code> returns 200 (DB; Redis when cache/queue use Redis)</td></tr><tr><td>Object storage</td><td><code>FILESYSTEM_DISK=s3</code> + <code>AWS_*</code> configured; migrate local assets with <code>php artisan storage:migrate-to-s3</code> (<a href="/developer-guide/object-storage">object-storage.md</a>)</td></tr></tbody></table><h2 id="frontend-spa-deploy" tabindex="-1">Frontend SPA deploy <a class="header-anchor" href="#frontend-spa-deploy" aria-label="Permalink to &quot;Frontend SPA deploy&quot;">​</a></h2><p>Production builds are automated on merge to <code>main</code>. See <a href="/developer-guide/frontend-build-artifacts">frontend-build-artifacts.md</a>.</p><p><strong>Preferred:</strong> deploy from the <strong><code>build-artifacts</code></strong> branch (or GitHub Actions artifact <code>frontend-build</code>). On Laravel Forge, generate <code>/config.js</code> (<code>window.env</code>) from the site <code>.env</code> in the deploy script (<code>VITE_API_URL</code>, optional <code>VITE_APP_NAME</code> / <code>VITE_API_MODE</code>, and <code>VITE_REVERB_*</code>). Do not bake the API URL into CI.</p><p><strong>Manual fallback:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SaaS-Frontend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># VITE_* must be set at build time (see .env.example)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Publish <code>dist/</code> (or the <code>build-artifacts</code> tree) to your CDN/static host / web root.</p><p>Cache guidance:</p><ul><li><code>index.html</code> — short TTL or <code>no-cache</code> (always revalidate)</li><li>Hashed assets under <code>assets/</code> — long-lived immutable cache</li><li>Use <code>build-info.json</code> on the artifact branch to confirm which <code>main</code> commit was built</li></ul><p>Point <code>FRONTEND_URL</code> / <code>CORS_ALLOWED_ORIGINS</code> on the API at the SPA origin(s).</p><h2 id="required-background-processes" tabindex="-1">Required background processes <a class="header-anchor" href="#required-background-processes" aria-label="Permalink to &quot;Required background processes&quot;">​</a></h2><ol><li><strong>HTTP / PHP-FPM</strong> (or Laravel Cloud web process)</li><li><strong>Queue workers</strong> — all <code>ShouldQueue</code> notifications use the dedicated <code>emails</code> queue (<code>QueuesOnEmails</code>)<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:work</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --queue=emails,default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sleep=1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tries=3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout=60</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-time=3600</span></span></code></pre></div></li><li><strong>Reverb</strong> — supervised WebSocket process behind TLS<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reverb:start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --host=127.0.0.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port=8080</span></span></code></pre></div>See the <a href="/deployment/notifications">Notification System runbook</a> for environment variables, Supervisor examples, origin pinning, and health checks.</li><li><strong>Scheduler</strong> (every minute)<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cd /path/to/SaaS-Backend &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule:run</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span></span></code></pre></div></li></ol><p>Scheduled commands (all use <code>withoutOverlapping</code>):</p><ul><li><code>sanctum:prune-expired</code></li><li><code>subscriptions:expire</code></li><li><code>billing:run-consolidated</code></li><li><code>crm:send-due-notifications</code></li><li><code>notifications:prune --days=90</code> (weekly)</li><li><code>email-logs:prune</code> (weekly — retention from <code>EMAIL_LOGS_RETAIN_DAYS</code> / config <code>email.logs_retain_days</code>)</li></ul><h2 id="deploy-sequence" tabindex="-1">Deploy sequence <a class="header-anchor" href="#deploy-sequence" aria-label="Permalink to &quot;Deploy sequence&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> down</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --retry=60</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # optional platform-wide maintenance</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --optimize-autoloader</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or the equivalent discrete caches:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># php artisan config:cache &amp;&amp; php artisan route:cache &amp;&amp; php artisan event:cache &amp;&amp; php artisan view:cache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reverb:restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span></span></code></pre></div><p>After a Multi-Provider Email release, also run <code>php artisan email:migrate-tenant-mail-modes</code> once (see <a href="/deployment/upgrade">Upgrade Guide</a>). Restart queue workers whenever Central/Tenant mail credentials change in Settings.</p><p>Go-live smoke for mail:</p><ol><li>Central <strong>Settings → Mail</strong> — choose SMTP / Postmark / Mailgun (not Log/Array in production) → <strong>Send test</strong></li><li>Tenant <strong>Settings → Mail</strong> — system provider test (inherits Central) and/or custom provider test</li><li>Open <strong>Email logs</strong> (Central + Tenant) and confirm the test rows appear</li></ol><h3 id="migration-driven-releases-no-production-seeders" tabindex="-1">Migration-driven releases (no production seeders) <a class="header-anchor" href="#migration-driven-releases-no-production-seeders" aria-label="Permalink to &quot;Migration-driven releases (no production seeders)&quot;">​</a></h3><p>Default modules and tenant permissions ship through <strong>data migrations</strong> that run with <code>php artisan migrate --force</code>.</p><ul><li>Do <strong>not</strong> run <code>php artisan db:seed</code> / <code>CatalogSeeder</code> / role permission seeders in production to register modules or repair RBAC</li><li>New default-included modules use <code>DefaultModuleRegistrar</code> (insert-only catalog + missing-workspace installs)</li><li>New permissions use <code>TenantPermissionSynchronizer</code> (additive grants only)</li><li>Authentication has <strong>no</strong> authorization side effects; incomplete deploys are not silently “fixed” on login</li></ul><p>See <a href="/deployment/module-development">module-development.md</a> and <a href="/deployment/communication-templates">communication-templates.md</a>.</p><p>Notes:</p><ul><li>Tenant-only maintenance must use Tenant Settings (<code>maintenance_mode</code>), <strong>not</strong> <code>artisan down</code>.</li><li>System settings are applied at runtime from the database; env/config cache alone does not replace DB-backed settings.</li></ul><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST /stripe/webhook</code></td><td>Cashier subscription mirror (+ BillingEngine when applicable)</td></tr><tr><td><code>POST /webhooks/gateways/{code}</code></td><td>Billing engine (all gateways)</td></tr></tbody></table><p>Both are CSRF-exempt and rate-limited (<code>throttle:webhooks</code>). Invalid Stripe/Creem signatures are rejected <strong>before</strong> full payload persistence. Both paths claim <code>webhook_logs</code> by <code>(payment_gateway_id, provider_event_id)</code> so the same provider event cannot double-settle.</p><p><strong>Failed processing:</strong> if handling throws after the log row is created, status is <code>failed</code> and a <strong>provider retry reprocesses</strong> that event (reclaims the failed row). Successful/<code>ignored</code> events still return “already handled”.</p><p>Prefer configuring Stripe to deliver business events to <code>/webhooks/gateways/stripe</code> and keep Cashier URL for subscription sync as documented in your Stripe dashboard. Creem: <code>POST /webhooks/gateways/creem</code> with <code>creem-signature</code>.</p><h2 id="module-cancel" tabindex="-1">Module cancel <a class="header-anchor" href="#module-cancel" aria-label="Permalink to &quot;Module cancel&quot;">​</a></h2><p>Cancelling a purchased module subscription calls the payment gateway (<code>cancelSubscription</code>) <strong>before</strong> marking the local row cancelled and clearing entitlements. If the provider call fails, the local subscription stays active and the API returns a validation error so billing does not silently continue while access is revoked.</p><h2 id="post-deploy-smoke" tabindex="-1">Post-deploy smoke <a class="header-anchor" href="#post-deploy-smoke" aria-label="Permalink to &quot;Post-deploy smoke&quot;">​</a></h2><ol><li>Central login + dashboard</li><li>Tenant login + dashboard</li><li>Create lead / task / communication template (module gates)</li><li>Lead WhatsApp picker opens <code>wa.me</code> when phone + template present</li><li>Stripe test webhook (or gateway health)</li><li>Forgot-password email leaves the queue</li><li>Suspend a test user → token immediately unusable</li><li><code>GET /up</code> healthy</li><li>Failed jobs empty: <code>php artisan queue:failed</code></li></ol><h2 id="rollback" tabindex="-1">Rollback <a class="header-anchor" href="#rollback" aria-label="Permalink to &quot;Rollback&quot;">​</a></h2><ol><li>Redeploy previous release artifact / image</li><li><code>php artisan migrate:rollback</code> only when the release’s migrations are known-safe to reverse</li><li><code>php artisan queue:restart</code></li><li>Verify <code>/up</code>, login, and billing webhook reachability</li></ol><h2 id="disaster-recovery-minimum" tabindex="-1">Disaster recovery (minimum) <a class="header-anchor" href="#disaster-recovery-minimum" aria-label="Permalink to &quot;Disaster recovery (minimum)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>RPO guidance</th><th>Restore</th></tr></thead><tbody><tr><td>MySQL (central + tenant DBs)</td><td>Point-in-time or daily dump</td><td>Restore dump; verify tenancy domains</td></tr><tr><td>Redis</td><td>Ephemeral OK</td><td>Clear + warm; workers will refill</td></tr><tr><td>Object storage (branding)</td><td>Daily</td><td>Sync from backup bucket; see <a href="/developer-guide/object-storage">object-storage.md</a></td></tr><tr><td><code>APP_KEY</code></td><td>Offline secure store</td><td>Required to decrypt encrypted attributes</td></tr></tbody></table><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><code>architecture/platform-freeze.md</code></li><li><code>authentication/authentication-production.md</code></li><li><code>billing/payment-gateways-production.md</code></li><li><code>authorization/tenant-rbac-production.md</code></li><li><code>modules/leads-production.md</code></li><li><code>modules/tasks-production.md</code></li><li><code>releases/rc1-production-readiness.md</code></li></ul>`,45)])])}const k=t(o,[["render",n]]);export{u as __pageData,k as default};
